import CloseIcon from '@mui/icons-material/Close';
import LocalMallRoundedIcon from '@mui/icons-material/LocalMallRounded';
import { Box, Button, Divider, Drawer, IconButton, List, ListItem, Stack, TextField, Typography, Container } from '@mui/material';
import React, { useEffect, useState } from 'react';
import BasketItem from './BasketItem';

export const Basket = (props) => {
    const {
        addToOrder,
        deleteFromOrder,
        cartOpen,
        closeCart = Function.prototype,
        order = [],
        removeFromOrder,
        promocodes = {},
        promocode,
        setPromocode
    } = props;

    const getDiscount = () => {
        if (promocode !== "") {
            for (const [promo, discount] of Object.entries(promocodes)) {
                if (promocode === promo) {
                    return discount / 100;
                }
            }
        }
        return 0;
    }

    const [discount, setDiscount] = useState(getDiscount());
    const sumWithoutDisc = order.reduce((acc, item) => {
        return acc + item.price * item.quantity;
    }, 0);
    const [sumWithDisc, setSumWithDiscount] = useState(parseInt(sumWithoutDisc * (1 - discount), 10));
    const [promtext, setPromtext] = useState(promocode === "" ? 'Promo code' : 'Applied');

    useEffect(() => {
        const newDiscount = getDiscount();
        setDiscount(newDiscount);
        if (newDiscount > 0) {
            setPromtext('Applied');
        } else {
            setPromtext('Promo code');
        }
    }, [promocodes, promocode]);

    useEffect(() => {
        setSumWithDiscount(parseInt(sumWithoutDisc * (1 - discount), 10));
    }, [sumWithoutDisc, discount]);

    const checkPromo = (promo) => {
        setPromocode(promo);
        for (const [promocode, discnt] of Object.entries(promocodes)) {
            if (promo === promocode) {
                setDiscount(discnt / 100);
                setPromtext('Applied');
                return;
            }
        }
        setPromtext('Promo code');
        setDiscount(0);
    }

    return (
        <Drawer
            anchor="right"
            open={cartOpen}
            onClose={closeCart}
            PaperProps={{
                sx: {
                    width: { xs: '100%', sm: '450px' },
                    backgroundColor: '#171A20',
                    backgroundImage: 'none',
                    borderLeft: '1px solid rgba(255, 255, 255, 0.06)',
                    p: 0,
                }
            }}
        >
            <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
                <Box sx={{ p: 3, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <Stack direction="row" spacing={2} alignItems="center">
                        <LocalMallRoundedIcon sx={{ color: 'primary.main' }} />
                        <Typography variant="h6" sx={{ fontWeight: 800, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                            Shopping Bag
                        </Typography>
                    </Stack>
                    <IconButton onClick={closeCart} sx={{ color: 'text.secondary', '&:hover': { color: 'white' } }}>
                        <CloseIcon />
                    </IconButton>
                </Box>

                <Divider sx={{ opacity: 0.1 }} />

                <Box sx={{ flexGrow: 1, overflowY: 'auto', p: 3 }}>
                    {!order.length ? (
                        <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 2, opacity: 0.5 }}>
                            <LocalMallRoundedIcon sx={{ fontSize: '3rem' }} />
                            <Typography variant="body1">Your bag is empty</Typography>
                            <Button variant="outlined" onClick={closeCart}>Continue Shopping</Button>
                        </Box>
                    ) : (
                        <List disablePadding>
                            {order.map((item) => (
                                <BasketItem 
                                    key={item.name + item.color + item.size} 
                                    addToOrder={addToOrder} 
                                    deleteFromOrder={deleteFromOrder} 
                                    removeFromOrder={removeFromOrder} 
                                    {...item} 
                                />
                            ))}
                        </List>
                    )}
                </Box>

                {order.length > 0 && (
                    <Box sx={{ p: 3, backgroundColor: 'rgba(255,255,255,0.02)', borderTop: '1px solid rgba(255,255,255,0.06)' }}>
                        <Stack spacing={2} sx={{ mb: 3 }}>
                            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <Typography variant="body2" sx={{ color: 'text.secondary' }}>Subtotal</Typography>
                                <Typography variant="body1" sx={{ fontWeight: 700 }}>{sumWithoutDisc} ₴</Typography>
                            </Box>
                            
                            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <TextField
                                    variant="standard"
                                    placeholder="Enter Promo Code"
                                    size="small"
                                    value={promocode}
                                    onChange={e => checkPromo(e.target.value)}
                                    sx={{ 
                                        width: '150px',
                                        '& .MuiInput-underline:before': { borderColor: 'rgba(255,255,255,0.1)' },
                                        '& .MuiInput-input': { fontSize: '0.875rem' }
                                    }}
                                />
                                {discount > 0 && (
                                    <Typography variant="body2" sx={{ color: 'primary.main', fontWeight: 700 }}>
                                        -{discount * 100}%
                                    </Typography>
                                )}
                            </Box>

                            <Divider sx={{ opacity: 0.1 }} />

                            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <Typography variant="h6" sx={{ fontWeight: 800 }}>Total</Typography>
                                <Typography variant="h6" sx={{ fontWeight: 800, color: 'primary.main' }}>
                                    {sumWithDisc} ₴
                                </Typography>
                            </Box>
                        </Stack>

                        <Button
                            fullWidth
                            variant="contained"
                            size="large"
                            href="/order"
                            sx={{
                                height: '56px',
                                borderRadius: '14px',
                                fontSize: '1rem',
                                fontWeight: 700,
                                boxShadow: '0 8px 24px rgba(212, 175, 55, 0.25)',
                            }}
                        >
                            Proceed to Checkout
                        </Button>
                    </Box>
                )}
            </Box>
        </Drawer>
    )
}

export default Basket;
